import React from 'react';

const RichTextEditor = ({ value, onChange, placeholder }) => {
  const insertFormatting = (format) => {
    const textarea = document.getElementById('proposal-content');
    if (!textarea) return;
    
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = value;
    let newText = text;
    let selectedText = text.substring(start, end);

    switch(format) {
      case 'bold':
        newText = text.substring(0, start) + '**' + selectedText + '**' + text.substring(end);
        break;
      case 'italic':
        newText = text.substring(0, start) + '_' + selectedText + '_' + text.substring(end);
        break;
      case 'heading':
        newText = text.substring(0, start) + '\n## ' + selectedText + '\n' + text.substring(end);
        break;
      case 'list':
        newText = text.substring(0, start) + '\n• ' + selectedText + '\n' + text.substring(end);
        break;
      default:
        break;
    }
    onChange(newText);
    
    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + 2, end + 2);
    }, 10);
  };

  return (
    <div className="rich-editor">
      <div className="editor-toolbar">
        <button type="button" onClick={() => insertFormatting('bold')}><strong>B</strong></button>
        <button type="button" onClick={() => insertFormatting('italic')}><em>I</em></button>
        <button type="button" onClick={() => insertFormatting('heading')}>H</button>
        <button type="button" onClick={() => insertFormatting('list')}>•</button>
      </div>
      <textarea
        id="proposal-content"
        className="editor-textarea"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder || "Rédigez votre proposition ici..."}
        rows="10"
      />
    </div>
  );
};

export default RichTextEditor;
